/// Executor for ImpersonationRequest flow
pub struct ImpersonationRequestFlowExecutor<H: ImpersonationRequestStepHandler> {
    handler: Arc<H>,
}

impl<H: ImpersonationRequestStepHandler> ImpersonationRequestFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<ImpersonationRequestFlowInstance, FlowError> {
        let mut instance = ImpersonationRequestFlowInstance::new(instance_id);
        instance.status = ImpersonationRequestFlowStatus::Running;
        instance.current_step = Some(ImpersonationRequestFlowStep::ValidateRequest);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut ImpersonationRequestFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            ImpersonationRequestFlowStep::ValidateRequest => {
                self.handler.handle_validate_request(instance).await?
            }
            ImpersonationRequestFlowStep::CheckValidation => {
                let next = self.handler.evaluate_check_validation(instance).await?;
                Some(next)
            }
            ImpersonationRequestFlowStep::LogValidationError => {
                self.handler.handle_log_validation_error(instance).await?
            }
            ImpersonationRequestFlowStep::CheckConcurrentLimit => {
                self.handler.handle_check_concurrent_limit(instance).await?
            }
            ImpersonationRequestFlowStep::VerifyLimit => {
                let next = self.handler.evaluate_verify_limit(instance).await?;
                Some(next)
            }
            ImpersonationRequestFlowStep::LogLimitExceeded => {
                self.handler.handle_log_limit_exceeded(instance).await?
            }
            ImpersonationRequestFlowStep::CreateSession => {
                self.handler.handle_create_session(instance).await?
            }
            ImpersonationRequestFlowStep::NotifyTargetUser => {
                self.handler.handle_notify_target_user(instance).await?
            }
            ImpersonationRequestFlowStep::LogSessionStart => {
                self.handler.handle_log_session_start(instance).await?
            }
            ImpersonationRequestFlowStep::MonitorSession => {
                self.handler.handle_monitor_session(instance).await?
            }
            ImpersonationRequestFlowStep::LogSessionEnd => {
                self.handler.handle_log_session_end(instance).await?
            }
            ImpersonationRequestFlowStep::ExpireSession => {
                self.handler.handle_expire_session(instance).await?
            }
            ImpersonationRequestFlowStep::LogExpiration => {
                self.handler.handle_log_expiration(instance).await?
            }
            ImpersonationRequestFlowStep::NotifyExpiry => {
                self.handler.handle_notify_expiry(instance).await?
            }
            ImpersonationRequestFlowStep::Complete => {
                self.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            ImpersonationRequestFlowStep::RequestFailed => {
                self.handler.handle_request_failed(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = ImpersonationRequestFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut ImpersonationRequestFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != ImpersonationRequestFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut ImpersonationRequestFlowInstance) {
        instance.status = ImpersonationRequestFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut ImpersonationRequestFlowInstance, error: impl Into<String>) {
        instance.status = ImpersonationRequestFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = ImpersonationRequestFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, ImpersonationRequestFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = ImpersonationRequestFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = ImpersonationRequestFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = ImpersonationRequestFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = ImpersonationRequestFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}
